VALUES
  ('social-worker-moex-02831', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列敘述何者錯誤？', '["民德（mores）是依民風裡所釐定之對或錯的處世和做事方法", "習俗是群體解決問題，處世與互動的方式", "任務團體（task groups）成立之主要目的在於完成原先釐定的任務", "自然團體（natural groups）是由於自然發生的事件所產生人與人之間互相排斥的團體"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02832', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列敘述何者錯誤？', '["同化（assimilation）是人類將新資訊納入既有知識體系或基模的認知之過程", "社會距離（social distance）是人際關係中人與人之間的高度親密關係", "利他主義（altruism）是助人的行為，出發點在於對他人的關懷，不是出自個人利益", "同性戀恐懼（homophobia）指對於同志的恐懼和仇恨，沒有任何理性或根據"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02833', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據生態系統觀點，下列那一項敘述錯誤？', '["生態系統觀點強調雙重焦點：人與情境、系統與環境，以全人與環境交互作用並互相影響與被影響", "生態學是研究有機體與環境之間的學科，被應用分析人於情境中因應環境的挑戰與協調模式", "社會工作者在實務操作上只注重單向的影響", "在處遇關係上，個體和系統都會受到系統變遷作用的影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02834', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關X染色體易碎症（fragile X syndrome）的敘述，何者最正確？', '["脆弱的X染色體引發特納症候群（Turner’s syndrome）", "由母親只傳給女兒", "有缺陷的X染色體無法透過第21號染色體彌補其生物功能", "可能造成重度智能障礙"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02835', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '爸爸當著六個月大的嬰兒阿丹把玩具卡車藏在毛巾底下時，阿丹不知如何去搜尋玩具車，皮亞傑（Piaget） 的學說指出原因，即六個月大的嬰兒缺乏以下那一個概念？', '["物體恆存性（object permanence）", "自我中心（egocentrism）", "認知失平衡（cognitive disequilibrium）", "具體運思（concrete operation）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02836', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據依附理論及相關研究結果，下列有關影響親子關係的品質或依附型態（attachment style）的陳述，何 者錯誤？', '["焦慮型依附（anxious attachment）的子女是不夠信任父母", "父母的內在運作模式或依附型態與子女的依附型態有很高的相關", "個體在壓力的情境下較可能呈現真正的依附型態", "子女與母親的依附型態才重要，而與父親的依附型態對孩子未來人格發展的影響極為有限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02837', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關提供兒童及青少年精神與心理衛生之處遇，下列敘述何者錯誤？', '["應以整體性的角度評估兒童及家庭的處境", "兒童及青少年能夠完整的以語言充分表達內在感受及問題", "需探索兒童及青少年對健康問題反應的主觀經驗", "需個別評估兒童及青少年的問題，以提供個別化的處置"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02838', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據柯柏格（Kohlberg）的道德發展理論引發性別議題，以下相關敘述何者不合時宜？', '["柯柏格強調公正觀點（justice perspective）", "柯柏格認為個體權利考量是道德發展的初級層次，趨向集體共享價值取向", "柯柏格學說被認為有性別偏見（gender prejudice）", "學者季里根（Gilligan））認為女性強調人與人之間的友好連結，以及對他人的關懷關點（care perspective）才是解決道德倫理兩難的重心"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02839', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '呂太太，56 歲，丈夫為臺商，經年在外。2 個兒子皆已娶妻，她常告訴親朋好友，她先生、孩子都已不 要她，所以不值得再活下去。她食慾差、注意力變差、不安、來回走動、失眠、覺得都是因為自己的錯， 小孩和先生才不理她，經常吵著要自殺，此狀況已持續1個多月。呂太太最可能的診斷為何？', '["重鬱症（major depression）", "解離失調（dissociative disorder）", "適應障礙（adjustment disorder）", "更年期障礙（menopause）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02840', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '艾瑞克森（Erikson）認為老年人主要的發展任務為何？', '["成熟相對於自責", "責任相對於放棄", "成熟相對於失落", "統合相對於絕望"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
